class Node:
    def __init__(self, val: int = 0, left: 'Node' = None, right: 'Node' = None, next: 'Node' = None):
        self.val = val
        self.left = left
        self.right = right
        self.next = next

class Solution:
    def connect(self, root: 'Node') -> 'Node':
        if not root:
            return None

        level_start = root

        while level_start:
            dummy_head = Node(0)
            current_child = dummy_head

            current_node = level_start
            while current_node:
                if current_node.left:
                    current_child.next = current_node.left
                    current_child = current_node.left

                if current_node.right:
                    current_child.next = current_node.right
                    current_child = current_node.right

                current_node = current_node.next

            level_start = dummy_head.next

        return root
